// Global Kill Switch check
if ($env.KILL_SWITCH === 'true') {
  throw new Error('KILL_SWITCH_ACTIVE: Meta writes are globally disabled.');
}

// Parse Slack interactive payload
const payload = JSON.parse($json.body.payload);
const [plan_id, decision] = payload.actions[0].value.split('|');
return [{ json: { plan_id, decision, user: payload.user.name } }];

// Hard safety rules before any Meta write
const plan = $node["Load Plan"].item.json;
const actions = plan.actions || [];
const maxBudgetChangePct = parseFloat($env.MAX_DAILY_BUDGET_CHANGE_PCT || 20);
const minConversions = parseInt($env.MIN_CONVERSIONS_FOR_SCALE || 10);

const safeActions = actions.filter(action => {
  // Block scale if insufficient conversions
  if (action.action_type === 'scale_budget') {
    // Note: in a real system we should re-verify conversions from DB here
    if ((action.conversions || 0) < minConversions) {
      console.log(`BLOCKED scale on ${action.entity_id}: insufficient conversions`);
      return false;
    }
    // Block if budget change exceeds cap
    const changePct = Math.abs((action.delta?.budget_change_pct || 0));
    if (changePct > maxBudgetChangePct) {
      console.log(`BLOCKED scale on ${action.entity_id}: budget change ${changePct}% exceeds cap ${maxBudgetChangePct}%`);
      return false;
    }
  }
  return true;
});

return safeActions.map(a => ({ json: { ...a, plan_id: plan.plan_id } }));

